<template>
  <div>
    <b-row>
      <b-col lg="6" md="8" class="mx-auto my-5">
        <b-card title="Register">
          <b-form @submit.prevent.stop="submitHandler">
            <b-form-group label="UserName">
              <b-form-input
                v-model.trim="$v.form.userName.$model"
                :state="validateState('userName')"
              ></b-form-input>
              <b-form-invalid-feedback>
                UserName must be between 3 and 32 characters.
              </b-form-invalid-feedback>
            </b-form-group>
            <b-form-group label="Email">
              <b-form-input
                v-model.trim="$v.form.email.$model"
                :state="validateState('email')"
              ></b-form-input>
              <b-form-invalid-feedback>
                Invalid Email.
              </b-form-invalid-feedback>
            </b-form-group>
            <b-form-group label="Password">
              <b-form-input
                v-model.trim="$v.form.password.$model"
                :state="validateState('password')"
                type="password"
              ></b-form-input>
              <b-form-invalid-feedback>
                Password must be between 3 and 32 characters.
              </b-form-invalid-feedback>
            </b-form-group>
            <b-form-group label="Comfirm Password">
              <b-form-input
                v-model.trim="$v.form.comfirmPassword.$model"
                :state="validateState('comfirmPassword')"
                type="password"
              ></b-form-input>
              <b-form-invalid-feedback>
                Comfirm Password is invalid.
              </b-form-invalid-feedback>
            </b-form-group>
            <b-button type="submit" variant="success" block>Create</b-button>
          </b-form>
        </b-card>
      </b-col>
    </b-row>
  </div>
</template>

<script>
import {
  required,
  minLength,
  maxLength,
  email,
  sameAs,
} from "vuelidate/lib/validators";
import AccountService from "@/services/AccountService";

export default {
  data() {
    return {
      form: {
        userName: "",
        email: "",
        password: "",
        comfirmPassword: "",
      },
    };
  },
  validations: {
    form: {
      userName: { required, minLength: minLength(3), maxLength: maxLength(32) },
      email: { required, email },
      password: { required, minLength: minLength(3), maxLength: maxLength(32) },
      comfirmPassword: { required, sameAs: sameAs("password") },
    },
  },
  methods: {
    validateState(name) {
      const { $dirty, $error } = this.$v.form[name];
      return $dirty ? !$error : null;
    },
    async submitHandler(event) {
      this.$v.form.$touch();
      if (this.$v.form.$anyError) {
        return;
      }

      try {
        var response = await AccountService.register({
          userName: this.form.userName,
          email: this.form.email,
          password: this.form.password,
        });
        this.$router.push("/login");
      } catch (exception) {
        const { status, data } = exception.response;
        var message = "";
        switch (status) {
          case 422:
            data.errors.forEach((error) => {
              message += `${error.param}: ${error.msg}\n`;
            });
            break;
          case 403:
            message = data.message;
            break;
          case 400:
          default:
            message = "Something wrong.";
            break;
        }
        alert(message);
      }
    },
  },
};
</script>

<style></style>
